// math.ts
export const PI = 3.14159265358979;

export function circleArea(r: number): number {
  return PI * r * r;
}

export interface Point {
  x: number;
  y: number;
}

export class Vector {
  constructor(public x: number, public y: number) {}
  length(): number { return Math.sqrt(this.x ** 2 + this.y ** 2); }
}

// calculator.ts
export default class Calculator {
  add(a: number, b: number) { return a + b; }
  subtract(a: number, b: number) { return a - b; }
}

// Exporting a function as default:
// export default function parse(input: string) { ... }

// Inline — export keyword before the declaration
export const BASE_URL = 'https://api.example.com';

// Declaration first, export at the bottom (useful for large files)
function formatDate(date: Date): string {
  return date.toISOString().split('T')[0];
}
const DEFAULT_FORMAT = 'YYYY-MM-DD';

export { formatDate, DEFAULT_FORMAT };  // explicit list
export { formatDate as format };         // rename on export

import { PI, circleArea, Vector } from './math';

circleArea(5);   // 78.54

// Rename on import to avoid name collisions
import { Vector as MathVector } from './math';

import Calculator from './calculator';    // any name is valid for defaults
const calc = new Calculator();
calc.add(3, 4);   // 7

// Execute a module for its side effects (e.g., polyfills, registrations)
import './polyfills';
import 'reflect-metadata';   // Angular uses this for decorators

import type { User, Product } from './models';
// The above import is completely removed from compiled JS

// Mixed: import value and type from the same module
import { UserService, type UserConfig } from './user.service';

// src/app/auth/index.ts — barrel
export { AuthService } from './auth.service';
export { AuthGuard } from './auth.guard';
export { LoginComponent } from './login/login.component';
export type { AuthUser, Credentials } from './auth.models';
// Do NOT export internal helpers that aren't part of the public API

// Consumer — one import path instead of multiple deep paths
import { AuthService, AuthGuard, type AuthUser } from './auth';
// instead of:
// import { AuthService } from './auth/auth.service';
// import { AuthGuard } from './auth/auth.guard';

// Load a module on demand
async function loadChart() {
  const { ChartComponent } = await import('./chart/chart.component');
  // ChartComponent is now available
}

// Conditional loading
if (featureFlags.enableAdvancedEditor) {
  const { AdvancedEditor } = await import('./advanced-editor');
}

// Dynamic module path (string must be a literal or statically analyzable
// for bundlers to create the correct chunk)
const locale = 'fr';
const { translations } = await import(`./locales/${locale}`);

// user.service.ts — a module
import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import type { User } from './user.model';

@Injectable({ providedIn: 'root' })
export class UserService {
  constructor(private http: HttpClient) {}

  getUser(id: number) {
    return this.http.get<User>(`/api/users/${id}`);
  }
}

// app.routes.ts
import { Routes } from '@angular/router';

export const routes: Routes = [
  { path: '', redirectTo: 'home', pathMatch: 'full' },
  { path: 'home', loadComponent: () => import('./home/home.component').then(m => m.HomeComponent) },
  {
    path: 'admin',
    // Lazy-load an entire set of routes
    loadChildren: () => import('./admin/admin.routes').then(m => m.ADMIN_ROUTES),
    canActivate: [authGuard],
  },
];

// utils.ts — exports 10 functions
export function formatDate(d: Date): string { ... }
export function formatCurrency(n: number): string { ... }
// ... 8 more

// app.component.ts — only imports formatDate
import { formatDate } from './utils';

// Bundler: only formatDate ends up in the output bundle
// The other 9 functions are eliminated — tree-shaken

// With path alias — cleaner than relative traversal
import { UserService } from '@app/services/user.service';
// instead of: import { UserService } from '../../../services/user.service';

// counter.ts
let count = 0;
export function increment() { count++; }
export function getCount() { return count; }

// a.ts
import { increment, getCount } from './counter';
increment();  // count = 1

// b.ts
import { increment, getCount } from './counter';
increment();  // count = 2  — same module instance as a.ts

// getCount() returns 2 from both a.ts and b.ts

// clock.ts
export let now = new Date();
export function tick() { now = new Date(); }

// display.ts
import { now, tick } from './clock';

console.log(now);  // time at import
tick();
console.log(now);  // updated time — live binding reflects new value
// This is different from CommonJS where you'd get a snapshot copy

// ✗ Circular: a.ts imports b.ts, b.ts imports a.ts
// a.ts:
import { bFunc } from './b';
export const aValue = 'A';

// b.ts:
import { aValue } from './a';
export function bFunc() { return aValue; }
// aValue may be undefined when bFunc is first called — module not yet initialised

// ✓ Fix: extract shared value to a third module
// shared.ts: export const sharedValue = '...';
// Both a.ts and b.ts import from shared.ts

// ── CommonJS (Node.js, pre-ESM) ──────────────────────────────────────────
// Synchronous. require() returns a snapshot copy (not live bindings).
const { PI } = require('./math');
module.exports = { add, subtract };
module.exports.default = Calculator;

// ── AMD (old browser async loading, RequireJS) ───────────────────────────
// Rarely seen today. Async loading via define() callback.
define(['./math'], function(math) {
  return { /* ... */ };
});

// ── ES Modules (current standard) ───────────────────────────────────────
// Static, live bindings, tree-shakeable, works in browsers natively.
import { PI } from './math.js';
export default class Calculator {}

// ── TypeScript compiles to... ────────────────────────────────────────────
// By default: CommonJS for Node.js targets
// For Angular/Vite/browser: ESM (tsconfig: "module": "ESNext")

import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { UserCardComponent } from './user-card/user-card.component';
import { SearchInputComponent } from '../shared/search-input.component';

@Component({
  selector: 'app-user-list',
  standalone: true,
  // Angular imports match ES module imports: explicit, co-located
  imports: [CommonModule, RouterLink, UserCardComponent, SearchInputComponent],
  template: `
    <app-search-input (search)="query.set($event)" />
    @for (user of filteredUsers(); track user.id) {
      <app-user-card [user]="user" [routerLink]="['/users', user.id]" />
    }
  `,
})
export class UserListComponent {
  users = signal<User[]>([]);
  query = signal('');
  filteredUsers = computed(() =>
    this.users().filter(u => u.name.toLowerCase().includes(this.query().toLowerCase()))
  );
}

// user.service.spec.ts
import { TestBed } from '@angular/core/testing';
import { HttpClientTestingModule, HttpTestingController } from '@angular/common/http/testing';
import { UserService } from './user.service';

describe('UserService', () => {
  let service: UserService;
  let httpMock: HttpTestingController;

  beforeEach(() => {
    TestBed.configureTestingModule({
      imports: [HttpClientTestingModule],
    });
    service = TestBed.inject(UserService);
    httpMock = TestBed.inject(HttpTestingController);
  });

  it('fetches a user by id', () => {
    service.getUser(1).subscribe(user => {
      expect(user.name).toBe('Deiva');
    });

    const req = httpMock.expectOne('/api/users/1');
    req.flush({ id: 1, name: 'Deiva' });
    httpMock.verify();
  });
});
